import Foundation

enum Environment {
    case development
    case staging
    case production
}

class NetworkManager {
    
    private let baseURL: String
    
    init(environment: Environment) {
        switch environment {
        case .development:
            baseURL = "https://api.dev.example.com"
        case .staging:
            baseURL = "https://api.staging.example.com"
        case .production:
            baseURL = "https://api.example.com"
        }
    }
    
    func fetchUserData(completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/user") else { return }
        URLSession.shared.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            if let data = data {
                completion(.success(data))
            }
        }.resume()
    }
    
    func authenticateUser(username: String, password: String, completion: @escaping (Result<Data, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/authenticate") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        let body = "username=\(username)&password=\(password)"
        request.httpBody = body.data(using: .utf8)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            if let data = data {
                completion(.success(data))
            }
        }.resume()
    }
}